const data = $input.first().json.extractedData;
const discrepancies = [];

// Cross-document validation (KlearNow's key feature)

// 1. BOL vs Invoice - Container match
if (data.bol.containerNumber) {
  // In real scenario, verify against master data
}

// 2. Value consistency
const invoiceTotal = data.invoice.totalValue;
const calculatedTotal = data.invoice.lineItems.reduce((sum, item) => sum + item.totalValue, 0);
if (Math.abs(invoiceTotal - calculatedTotal) > 1) {
  discrepancies.push({
    type: 'value_mismatch',
    severity: 'high',
    message: `Invoice total ($${invoiceTotal}) doesn't match line items ($${calculatedTotal})`,
    documents: ['invoice']
  });
}

// 3. Weight consistency
const invoiceWeight = data.packingList.totalWeight;
const weightPerItem = data.invoice.lineItems.reduce((sum, item) => sum + (item.quantity * 0.1), 0); // Rough estimate
if (Math.abs(invoiceWeight - weightPerItem) > 500) {
  discrepancies.push({
    type: 'weight_variance',
    severity: 'medium',
    message: `Declared weight (${invoiceWeight}kg) significantly different from estimated`,
    documents: ['packing_list', 'invoice']
  });
}

// 4. HS Code validation
data.invoice.lineItems.forEach((item, idx) => {
  if (item.hsCode.startsWith('8542')) { // Semiconductors
    discrepancies.push({
      type: 'controlled_item',
      severity: 'high',
      message: `Line ${idx + 1}: Semiconductor chips (${item.hsCode}) may require EAR license`,
      documents: ['invoice']
    });
  }
});

// 5. High-value check
if (data.invoice.totalValue > 250000) {
  discrepancies.push({
    type: 'high_value',
    severity: 'medium',
    message: `High-value shipment: $${data.invoice.totalValue}`,
    documents: ['invoice']
  });
}

return [{
  json: {
    ...$input.first().json,
    discrepancies,
    hasDiscrepancies: discrepancies.length > 0,
    criticalIssues: discrepancies.filter(d => d.severity === 'high').length,
    requiresHumanReview: discrepancies.filter(d => d.severity === 'high').length > 0
  }
}];

