// Auto-file clean entries (no discrepancies)
const data = $input.first().json;

// Calculate duties
const duties = data.extractedData.invoice.lineItems.map(item => ({
  hsCode: item.hsCode,
  description: item.description,
  value: item.totalValue,
  dutyRate: item.hsCode.startsWith('8542') ? 0.035 : 0.025, // 3.5% for semiconductors, 2.5% otherwise
  dutyAmount: item.totalValue * (item.hsCode.startsWith('8542') ? 0.035 : 0.025)
}));

const totalDuty = duties.reduce((sum, d) => sum + d.dutyAmount, 0);

return [{
  json: {
    ...data,
    customsEntry: {
      entryNumber: 'EE-' + Date.now().toString().slice(-8),
      filedAt: new Date().toISOString(),
      entryType: '01', // Consumption
      portOfEntry: data.extractedData.bol.portOfDischarge,
      importerNumber: data.extractedData.invoice.consignee.taxId,
      suretyBond: 'SINGLE_TRANSACTION',
      merchandise: duties,
      totalDuty: Math.round(totalDuty * 100) / 100,
      mpf: Math.min(614.35, data.extractedData.invoice.totalValue * 0.003464), // Merchandise Processing Fee
      hmf: data.extractedData.invoice.totalValue * 0.00125, // Harbor Maintenance Fee
      status: 'FILED',
      filingMethod: 'ACE' // Automated Commercial Environment
    }
  }
}];

